// Extract and clean the incoming data
const items = $input.all();
const data = items[0].json;

return [{
  json: {
    senderName: data.name || data.from || 'Unknown',
    senderEmail: data.email || data.sender || '',
    subject: data.subject || 'No Subject',
    message: data.message || data.body || data.text || '',
    timestamp: new Date().toISOString(),
    // Classify the email type
    category: classifyEmail(data.message || data.body || '')
  }
}];

function classifyEmail(text) {
  const lower = text.toLowerCase();
  if (lower.includes('price') || lower.includes('cost') || lower.includes('quote')) return 'pricing';
  if (lower.includes('support') || lower.includes('help') || lower.includes('issue') || lower.includes('problem')) return 'support';
  if (lower.includes('order') || lower.includes('delivery') || lower.includes('shipping')) return 'order';
  if (lower.includes('refund') || lower.includes('return') || lower.includes('cancel')) return 'refund';
  if (lower.includes('partner') || lower.includes('collaboration') || lower.includes('business')) return 'partnership';
  return 'general';
}

